(function(g){g.SD_ANNUAL={"varshesh":{"sun":{"en":"A year ruled by the Sun — themes of authority, recognition, health and self-assertion dominate. Leadership opportunities, dealings with government or seniors, and a stronger sense of purpose mark the twelve months. Guard against ego and pace your energy.","hi":"यह साल सूर्य के अधीन है — पद, पहचान, सेहत और अपनी बात रखने के विषय सामने रहेंगे। नेतृत्व के मौक़े, सरकारी या बड़े लोगों से काम, और अपने मक़सद को लेकर साफ़ सोच इन बारह महीनों की पहचान है। अहं से बचिए और ऊर्जा सोच-समझकर ख़र्च कीजिए।","te":"ఈ సంవత్సరం సూర్యుడి ఆధిపత్యంలో ఉంది — పదవి, గుర్తింపు, ఆరోగ్యం, మీ మాట నిలబెట్టుకోవడం ముందుంటాయి. నాయకత్వ అవకాశాలు, ప్రభుత్వ లేదా పెద్దలతో పని, మీ లక్ష్యంపై స్పష్టత ఈ పన్నెండు నెలల గుర్తు. అహం వద్దు, శక్తిని ఆలోచించి ఖర్చు చేయండి."},"moon":{"en":"A year ruled by the Moon — emotions, home, mother, and public connection take centre stage. It is a year of nurturing and being nurtured, of travel and shifting moods. Protect your peace of mind and stay close to well-wishers.","hi":"यह साल चंद्र के अधीन है — भावनाएँ, घर, माँ और लोगों से जुड़ाव केंद्र में रहेंगे। यह साल किसी का सहारा बनने और सहारा पाने का है, यात्रा और बदलते मन का भी। अपने मन की शांति सँभालिए और शुभचिंतकों के क़रीब रहिए।","te":"ఈ సంవత్సరం చంద్రుడి ఆధిపత్యంలో ఉంది — భావాలు, ఇల్లు, తల్లి, జనంతో అనుబంధం కేంద్రంలో ఉంటాయి. ఇది ఎవరికైనా ఆసరా అవడానికీ, ఆసరా పొందడానికీ, ప్రయాణాలకూ, మారే మనసుకూ సంబంధించిన సంవత్సరం. మీ మనశ్శాంతిని కాపాడుకోండి, శ్రేయోభిలాషుల దగ్గర ఉండండి."},"mars":{"en":"A year ruled by Mars — energy, courage, property and bold action define it. Excellent for initiatives requiring drive, competition and technical skill; take care with anger, haste and disputes. Channel the fire into disciplined effort.","hi":"यह साल मंगल के अधीन है — ऊर्जा, हिम्मत, ज़मीन-जायदाद और बड़े क़दम इसकी पहचान हैं। जिन कामों में दम, मुक़ाबला और तकनीकी हुनर चाहिए, उनके लिए बढ़िया साल; ग़ुस्से, जल्दबाज़ी और झगड़ों से बचिए। इस जोश को अनुशासन के साथ काम में लगाइए।","te":"ఈ సంవత్సరం కుజుడి ఆధిపత్యంలో ఉంది — శక్తి, ధైర్యం, స్థిరాస్తి, పెద్ద అడుగులు దీని గుర్తు. బలం, పోటీ, సాంకేతిక నైపుణ్యం అవసరమైన పనులకు మంచి సంవత్సరం; కోపం, తొందరపాటు, గొడవలకు దూరంగా ఉండండి. ఈ ఉత్సాహాన్ని క్రమశిక్షణతో పనిలో పెట్టండి."},"mercury":{"en":"A year ruled by Mercury — communication, learning, business and intellect flourish. A fine year for study, trade, writing and negotiation; ideas flow and networks expand. Stay organized and verify details in all agreements.","hi":"यह साल बुध के अधीन है — बातचीत, पढ़ाई, व्यापार और बुद्धि से जुड़े काम फलते हैं। पढ़ाई, कारोबार, लेखन और सौदेबाज़ी के लिए बढ़िया साल; नए विचार आएँगे और संपर्क बढ़ेंगे। हिसाब-किताब व्यवस्थित रखिए और हर समझौते की बारीकी जाँच लीजिए।","te":"ఈ సంవత్సరం బుధుడి ఆధిపత్యంలో ఉంది — మాటలు, చదువు, వ్యాపారం, బుద్ధి సంబంధిత పనులు ఫలిస్తాయి. చదువు, వ్యాపారం, రచన, చర్చలకు మంచి సంవత్సరం; కొత్త ఆలోచనలు వస్తాయి, సంబంధాలు పెరుగుతాయి. లెక్కలు క్రమంగా ఉంచండి, ప్రతి ఒప్పందంలో వివరాలు సరిచూసుకోండి."},"jupiter":{"en":"A year ruled by Jupiter — the most auspicious of year lords. Wisdom, growth, good fortune, teachers, finance and family blessings flow generously. A wonderful year to expand, learn, marry, or begin ventures. Give generously and act with faith.","hi":"यह साल गुरु के अधीन है — सभी वर्ष-स्वामियों में सबसे शुभ। ज्ञान, तरक़्क़ी, भाग्य, गुरुजन, पैसा और पारिवारिक आशीर्वाद खुलकर मिलते हैं। कुछ बड़ा शुरू करने, पढ़ने, शादी करने या नया काम आरंभ करने के लिए बहुत अच्छा साल। खुले हाथ से दान कीजिए और भरोसे के साथ आगे बढ़िए।","te":"ఈ సంవత్సరం గురువు ఆధిపత్యంలో ఉంది — సంవత్సర అధిపతుల్లో అత్యంత శుభమైనది. జ్ఞానం, ఎదుగుదల, అదృష్టం, గురువులు, డబ్బు, కుటుంబ ఆశీర్వాదాలు ఉదారంగా లభిస్తాయి. పెద్దది ఏదైనా మొదలుపెట్టడానికి, చదవడానికి, పెళ్లికి, కొత్త పనికి చాలా మంచి సంవత్సరం. ఉదారంగా దానం చేయండి, నమ్మకంతో ముందుకు సాగండి."},"venus":{"en":"A year ruled by Venus — relationships, comforts, arts, and financial pleasures blossom. Romance, marriage, beauty, luxury and creative pursuits are favoured; enjoyment comes easily. Savour in moderation and invest in lasting beauty.","hi":"यह साल शुक्र के अधीन है — रिश्ते, सुख-सुविधा, कला और आर्थिक ख़ुशियाँ बढ़ती हैं। प्यार, शादी, सुंदरता, आराम और रचनात्मक काम के लिए अनुकूल समय; ख़ुशी सहज मिलती है। संयम रखिए और जो चीज़ें लंबे समय तक साथ दें, उन्हीं में पैसा लगाइए।","te":"ఈ సంవత్సరం శుక్రుడి ఆధిపత్యంలో ఉంది — బంధాలు, సుఖం, కళలు, ఆర్థిక ఆనందాలు పెరుగుతాయి. ప్రేమ, పెళ్లి, అందం, సౌకర్యం, సృజనాత్మక పనులకు అనుకూల సమయం; ఆనందం సహజంగా వస్తుంది. మితంగా అనుభవించండి, కలకాలం నిలిచే వాటిలో పెట్టుబడి పెట్టండి."},"saturn":{"en":"A year ruled by Saturn — discipline, responsibility, and lasting foundations are the themes. Progress is steady rather than swift; hard work now builds durable results. Protect health, honour commitments, and avoid shortcuts. Patience is richly rewarded.","hi":"यह साल शनि के अधीन है — अनुशासन, ज़िम्मेदारी और टिकाऊ नींव इसके मुख्य स्वर हैं। तरक़्क़ी तेज़ नहीं, स्थिर रहेगी; आज की मेहनत आगे चलकर पक्का फल देती है। सेहत सँभालिए, किए गए वादे निभाइए और शॉर्टकट से दूर रहिए। धैर्य का यहाँ पूरा इनाम मिलता है।","te":"ఈ సంవత్సరం శని ఆధిపత్యంలో ఉంది — క్రమశిక్షణ, బాధ్యత, నిలిచే పునాదులు దీని ముఖ్య స్వరాలు. ఎదుగుదల వేగంగా కాదు, స్థిరంగా ఉంటుంది; ఈనాటి శ్రమ ముందు ముందు గట్టి ఫలితం ఇస్తుంది. ఆరోగ్యం కాపాడుకోండి, ఇచ్చిన మాట నిలబెట్టుకోండి, షార్ట్‌కట్‌లకు దూరంగా ఉండండి. ఇక్కడ ఓపికకు పూర్తి ఫలితం ఉంటుంది."},"rahu":{"en":"A year ruled by Rahu — ambition, foreign matters, technology and unconventional gains rise. Sudden opportunities and unusual paths appear; the year rewards boldness tempered with ethics. Verify shortcuts and stay grounded amid rapid change.","hi":"यह साल राहु के अधीन है — महत्वाकांक्षा, विदेश, तकनीक और लीक से हटकर फ़ायदे बढ़ते हैं। अचानक मौक़े और अलग तरह के रास्ते खुलेंगे; ईमानदारी के साथ उठाई गई हिम्मत इस साल रंग लाती है। शॉर्टकट परख लीजिए और तेज़ बदलाव के बीच ज़मीन से जुड़े रहिए।","te":"ఈ సంవత్సరం రాహువు ఆధిపత్యంలో ఉంది — ఆకాంక్ష, విదేశం, టెక్నాలజీ, లీక్ నుంచి బయటపడే లాభాలు పెరుగుతాయి. అకస్మాత్తు అవకాశాలు, భిన్నమైన దారులు తెరుచుకుంటాయి; నిజాయితీతో చూపిన ధైర్యం ఈ సంవత్సరం ఫలిస్తుంది. షార్ట్‌కట్‌లు పరిశీలించండి, వేగవంతమైన మార్పుల మధ్య నిలకడగా ఉండండి."},"ketu":{"en":"A year ruled by Ketu — introspection, spirituality, research and letting go come to the fore. Material matters may feel secondary to inner growth; it is a fine year for sadhana, study and simplification. Trust your intuition and release what no longer serves.","hi":"यह साल केतु के अधीन है — आत्म-चिंतन, अध्यात्म, रिसर्च और मोह छोड़ना आगे आते हैं। भौतिक बातें भीतर के विकास के आगे छोटी लग सकती हैं; साधना, अध्ययन और ज़िंदगी को सरल बनाने के लिए बढ़िया साल। अपने मन की आवाज़ पर भरोसा कीजिए और जो अब काम का नहीं, उसे जाने दीजिए।","te":"ఈ సంవత్సరం కేతువు ఆధిపత్యంలో ఉంది — ఆత్మ చింతన, ఆధ్యాత్మికత, పరిశోధన, వదిలిపెట్టడం ముందుకు వస్తాయి. భౌతిక విషయాలు అంతర్గత ఎదుగుదల ముందు చిన్నవిగా అనిపించవచ్చు; సాధన, అధ్యయనం, జీవితాన్ని సరళం చేసుకోవడానికి మంచి సంవత్సరం. మీ అంతరాత్మను నమ్మండి, ఇక పనికిరానిదాన్ని వదిలేయండి."}},"muntha":{"1":{"en":"The Muntha in the 1st house energizes your whole year — vitality, initiative and personal prominence are strong. A year to lead and to put yourself forward.","hi":"मुंथा पहले भाव में है, जो पूरे साल को ऊर्जा देती है — सेहत, पहल और अपनी पहचान मज़बूत रहेगी। यह साल आगे बढ़कर नेतृत्व करने और ख़ुद को सामने रखने का है।","te":"ముంథ మొదటి భావంలో ఉంది, ఇది సంవత్సరం మొత్తానికి శక్తినిస్తుంది — ఆరోగ్యం, చొరవ, మీ గుర్తింపు బలంగా ఉంటాయి. ముందుండి నడిపించడానికి, మిమ్మల్ని మీరు ముందుకు తీసుకురావడానికి ఇది సంవత్సరం."},"2":{"en":"The Muntha in the 2nd house turns the year toward wealth, family and speech — earnings and savings gain focus, and family matters are prominent.","hi":"मुंथा दूसरे भाव में है, तो साल का रुख़ पैसे, परिवार और वाणी की ओर रहेगा — कमाई और बचत पर ध्यान बढ़ेगा, और परिवार से जुड़े मामले सामने रहेंगे।","te":"ముంథ రెండవ భావంలో ఉంది, కాబట్టి సంవత్సరం డబ్బు, కుటుంబం, మాట వైపు మళ్లుతుంది — సంపాదన, పొదుపు మీద దృష్టి పెరుగుతుంది, కుటుంబ విషయాలు ముందుంటాయి."},"3":{"en":"The Muntha in the 3rd house favours courage, effort and communication — a year of initiative, short travels and progress through your own drive.","hi":"मुंथा तीसरे भाव में है, जो हिम्मत, मेहनत और बातचीत के पक्ष में है — पहल करने, छोटी यात्राओं और अपने दम पर आगे बढ़ने का साल।","te":"ముంథ మూడవ భావంలో ఉంది, ఇది ధైర్యం, కృషి, మాటలకు అనుకూలం — చొరవ, చిన్న ప్రయాణాలు, సొంత శక్తితో ముందుకు సాగే సంవత్సరం."},"4":{"en":"The Muntha in the 4th house centres the year on home, property, mother and inner peace — matters of residence and emotional foundation come forward.","hi":"मुंथा चौथे भाव में है, तो साल का केंद्र घर, ज़मीन-जायदाद, माँ और मन की शांति रहेगा — रहने की जगह और भावनात्मक नींव से जुड़ी बातें सामने आएँगी।","te":"ముంథ నాలుగవ భావంలో ఉంది, కాబట్టి సంవత్సర కేంద్రం ఇల్లు, స్థిరాస్తి, తల్లి, మనశ్శాంతి — నివాసం, భావోద్వేగ పునాదికి సంబంధించిన విషయాలు ముందుకు వస్తాయి."},"5":{"en":"The Muntha in the 5th house brings creativity, children, learning and romance into focus — an auspicious placement for joy, education and self-expression.","hi":"मुंथा पाँचवें भाव में है, जो रचनात्मकता, संतान, पढ़ाई और प्यार को केंद्र में लाती है — ख़ुशी, शिक्षा और ख़ुद को व्यक्त करने के लिए शुभ स्थिति।","te":"ముంథ ఐదవ భావంలో ఉంది, ఇది సృజన, సంతానం, చదువు, ప్రేమను కేంద్రంలోకి తెస్తుంది — ఆనందం, విద్య, ఆత్మ వ్యక్తీకరణకు శుభ స్థితి."},"6":{"en":"The Muntha in the 6th house emphasizes work, service and overcoming obstacles — a year to defeat rivals and resolve debts through steady effort; guard health.","hi":"मुंथा छठे भाव में है, जो काम, सेवा और मुश्किलों पर जीत को आगे लाती है — लगातार मेहनत से विरोधियों पर जीत और क़र्ज़ से छुटकारा; सेहत का ध्यान रखिए।","te":"ముంథ ఆరవ భావంలో ఉంది, ఇది పని, సేవ, ఇబ్బందులపై విజయాన్ని ముందుకు తెస్తుంది — నిరంతర కృషితో ప్రత్యర్థులపై విజయం, అప్పుల నుండి విముక్తి; ఆరోగ్యం చూసుకోండి."},"7":{"en":"The Muntha in the 7th house highlights partnerships, marriage and public dealings — relationships and collaborations take centre stage this year.","hi":"मुंथा सातवें भाव में है, जो साझेदारी, शादी और लोगों से व्यवहार को उभारती है — इस साल रिश्ते और मिलकर किए गए काम केंद्र में रहेंगे।","te":"ముంథ ఏడవ భావంలో ఉంది, ఇది భాగస్వామ్యం, పెళ్లి, జనంతో వ్యవహారాన్ని ముందుకు తెస్తుంది — ఈ సంవత్సరం బంధాలు, కలిసి చేసే పనులు కేంద్రంలో ఉంటాయి."},"8":{"en":"The Muntha in the 8th house asks for caution and consolidation — a year of transformation where patience, prudence and health-care matter most. Avoid big risks.","hi":"मुंथा आठवें भाव में है, जो सावधानी और सँभालने की माँग करती है — बदलाव का साल, जहाँ धैर्य, समझदारी और सेहत का ध्यान सबसे ज़रूरी है। बड़े जोखिम टालिए।","te":"ముంథ ఎనిమిదవ భావంలో ఉంది, ఇది జాగ్రత్తను, సర్దుబాటును కోరుతుంది — మార్పుల సంవత్సరం, ఇక్కడ ఓపిక, వివేకం, ఆరోగ్య జాగ్రత్తే ముఖ్యం. పెద్ద రిస్క్‌లు వద్దు."},"9":{"en":"The Muntha in the 9th house is highly fortunate — fortune, higher learning, dharma and travel are blessed. A year of luck, wisdom and meaningful journeys.","hi":"मुंथा नवें भाव में है, जो बहुत भाग्यशाली है — भाग्य, आगे की पढ़ाई, धर्म और यात्रा पर कृपा रहेगी। यह क़िस्मत, ज्ञान और सार्थक यात्राओं का साल है।","te":"ముంథ తొమ్మిదవ భావంలో ఉంది, ఇది చాలా అదృష్టకరం — అదృష్టం, ఉన్నత విద్య, ధర్మం, ప్రయాణాలపై అనుగ్రహం ఉంటుంది. ఇది అదృష్టం, జ్ఞానం, అర్థవంతమైన ప్రయాణాల సంవత్సరం."},"10":{"en":"The Muntha in the 10th house favours career and status — professional achievement, recognition and public standing rise. An excellent year for work goals.","hi":"मुंथा दसवें भाव में है, जो करियर और पद के पक्ष में है — काम में उपलब्धि, पहचान और समाज में स्थिति बढ़ती है। नौकरी-कारोबार के लक्ष्यों के लिए बढ़िया साल।","te":"ముంథ పదవ భావంలో ఉంది, ఇది కెరీర్, పదవికి అనుకూలం — పనిలో విజయం, గుర్తింపు, సమాజంలో స్థానం పెరుగుతాయి. ఉద్యోగ, వ్యాపార లక్ష్యాలకు మంచి సంవత్సరం."},"11":{"en":"The Muntha in the 11th house is excellent for gains — income, fulfilled wishes, networks and elder siblings prosper. One of the most favourable placements for the year.","hi":"मुंथा ग्यारहवें भाव में है, जो लाभ के लिए बहुत अच्छी है — आमदनी, पूरी होती इच्छाएँ, संपर्क और बड़े भाई-बहन का साथ फलता है। साल की सबसे अनुकूल स्थितियों में से एक।","te":"ముంథ పదకొండవ భావంలో ఉంది, ఇది లాభాలకు చాలా మంచిది — ఆదాయం, తీరే కోరికలు, సంబంధాలు, అన్నదమ్ముల సహకారం ఫలిస్తాయి. సంవత్సరానికి అత్యంత అనుకూల స్థితుల్లో ఒకటి."},"12":{"en":"The Muntha in the 12th house turns toward expenses, foreign matters, spirituality and rest — a year for inner work, letting go, and careful handling of resources.","hi":"मुंथा बारहवें भाव में है, तो रुख़ ख़र्च, विदेश, अध्यात्म और आराम की ओर रहेगा — भीतर के काम, मोह छोड़ने और पैसे को सँभालकर चलाने का साल।","te":"ముంథ పన్నెండవ భావంలో ఉంది, కాబట్టి దృష్టి ఖర్చులు, విదేశం, ఆధ్యాత్మికత, విశ్రాంతి వైపు ఉంటుంది — అంతర్గత కృషి, వదిలిపెట్టడం, డబ్బును జాగ్రత్తగా నడపడం."}},"labels":{"title":{"en":"Annual Forecast","hi":"वार्षिक भविष्यफल","te":"వార్షిక ఫలితం"},"subtitle":{"en":"Your year ahead — Varshaphal solar-return analysis","hi":"आपका आने वाला साल — वर्षफल कुंडली के आधार पर","te":"మీ రాబోయే సంవత్సరం — వర్షఫల జాతకం ఆధారంగా"},"forYear":{"en":"For the year","hi":"साल","te":"సంవత్సరం"},"summary":{"en":"Your Year at a Glance","hi":"एक नज़र में आपका साल","te":"ఒక్క చూపులో మీ సంవత్సరం"},"chart":{"en":"Varshaphal Chart","hi":"वर्षफल कुंडली","te":"వర్షఫల జాతకం"},"varshaLagna":{"en":"Annual Ascendant (Varsha Lagna)","hi":"वर्ष लग्न","te":"వర్ష లగ్నం"},"yearLord":{"en":"Year Lord (Varshesh)","hi":"वर्ष का स्वामी (वर्षेश)","te":"సంవత్సర అధిపతి (వర్షేశుడు)"},"munthaLabel":{"en":"Muntha","hi":"मुंथा","te":"ముంథ"},"solarReturn":{"en":"Solar Return moment","hi":"सूर्य के लौटने का समय","te":"సూర్యుడు తిరిగి వచ్చిన సమయం"},"yearTheme":{"en":"The Character of Your Year","hi":"आपके साल का मिज़ाज","te":"మీ సంవత్సర స్వభావం"},"munthaTheme":{"en":"Where the Year's Focus Falls","hi":"साल का ध्यान कहाँ रहेगा","te":"సంవత్సర దృష్టి ఎక్కడ ఉంటుంది"},"months":{"en":"Month-by-Month Outlook","hi":"महीने-दर-महीने","te":"నెల వారీగా"},"bestDates":{"en":"Auspicious Dates This Year","hi":"इस साल के शुभ दिन","te":"ఈ సంవత్సరపు శుభ దినాలు"},"remedies":{"en":"Remedies for the Year","hi":"साल के लिए उपाय","te":"సంవత్సరానికి పరిహారాలు"},"favourable":{"en":"Favourable","hi":"अनुकूल","te":"అనుకూలం"},"steady":{"en":"Steady","hi":"सामान्य","te":"సాధారణం"},"care":{"en":"Take care","hi":"सँभलकर","te":"జాగ్రత్త"},"method":{"en":"This forecast is cast from your Varshaphal — the chart of the exact moment the Sun returned to its birth position this year (Tajika tradition) — combined with your running dasha and monthly transits. Placements are verifiable against your free Kundli report.","hi":"यह भविष्यफल आपकी वर्षफल कुंडली से बना है — यानी उस ठीक पल की कुंडली जब इस साल सूर्य आपकी जन्म-स्थिति पर लौटा (ताजिक पद्धति) — साथ में आपकी चल रही दशा और महीने के गोचर भी जोड़े गए हैं। सभी स्थितियाँ निःशुल्क कुंडली रिपोर्ट से मिलाई जा सकती हैं।","te":"ఈ ఫలితం మీ వర్షఫల జాతకం ఆధారంగా తయారైంది — అంటే ఈ సంవత్సరం సూర్యుడు మీ జన్మ స్థానానికి తిరిగి వచ్చిన సరిగ్గా ఆ క్షణపు జాతకం (తాజిక పద్ధతి) — దానితో పాటు మీ ప్రస్తుత దశ, నెలవారీ గోచారాలు కూడా కలిపాం. అన్ని స్థితులూ ఉచిత జాతక రిపోర్ట్‌తో సరిపోల్చుకోవచ్చు."},"disclaimer":{"en":"Offered in the spirit of tradition for reflection and planning. Renew each year for a fresh Varshaphal. Your effort and choices shape the year.","hi":"परंपरा की भावना से, सोच-विचार और योजना के लिए प्रस्तुत। हर साल नई वर्षफल कुंडली बनवाइए। साल कैसा बीतेगा, यह आपकी मेहनत और फ़ैसलों से तय होता है।","te":"సంప్రదాయ భావనతో, ఆలోచన, ప్రణాళిక కోసం అందించినది. ప్రతి సంవత్సరం కొత్త వర్షఫలం చేయించుకోండి. సంవత్సరం ఎలా గడుస్తుందన్నది మీ కృషి, నిర్ణయాలే నిర్ణయిస్తాయి."}},"monthHint":{"sun":{"focusEn":"authority and health","oppEn":"recognition at work","avoidEn":"ego clashes","focusHi":"पद और सेहत","oppHi":"काम में पहचान","avoidHi":"अहं की टक्कर","focusTe":"పదవి, ఆరోగ్యం","oppTe":"పనిలో గుర్తింపు","avoidTe":"అహం ఘర్షణ"},"moon":{"focusEn":"home and emotions","oppEn":"nurturing connections","avoidEn":"overthinking","focusHi":"घर और भावनाएँ","oppHi":"अपनों से जुड़ाव","avoidHi":"ज़्यादा सोचना","focusTe":"ఇల్లు, భావాలు","oppTe":"ఆత్మీయ బంధాలు","avoidTe":"అతిగా ఆలోచించడం"},"mars":{"focusEn":"energy and property","oppEn":"bold initiatives","avoidEn":"arguments and haste","focusHi":"ऊर्जा और ज़मीन-जायदाद","oppHi":"बड़े क़दम","avoidHi":"बहस और जल्दबाज़ी","focusTe":"శక్తి, స్థిరాస్తి","oppTe":"పెద్ద అడుగులు","avoidTe":"వాదనలు, తొందరపాటు"},"mercury":{"focusEn":"communication and finances","oppEn":"networking and deals","avoidEn":"careless paperwork","focusHi":"बातचीत और पैसा","oppHi":"संपर्क और सौदे","avoidHi":"काग़ज़ी काम में लापरवाही","focusTe":"మాటలు, డబ్బు","oppTe":"సంబంధాలు, ఒప్పందాలు","avoidTe":"కాగితపు పనిలో అజాగ్రత్త"},"jupiter":{"focusEn":"growth and learning","oppEn":"expansion and guidance","avoidEn":"overcommitment","focusHi":"तरक़्क़ी और सीखना","oppHi":"विस्तार और मार्गदर्शन","avoidHi":"ज़्यादा वादे करना","focusTe":"ఎదుగుదల, నేర్చుకోవడం","oppTe":"విస్తరణ, మార్గదర్శనం","avoidTe":"ఎక్కువ మాట ఇవ్వడం"},"venus":{"focusEn":"relationships and comfort","oppEn":"romance and creativity","avoidEn":"overindulgence","focusHi":"रिश्ते और सुख","oppHi":"प्यार और रचनात्मकता","avoidHi":"ज़रूरत से ज़्यादा ख़र्च","focusTe":"బంధాలు, సుఖం","oppTe":"ప్రేమ, సృజన","avoidTe":"అతి ఖర్చు"},"saturn":{"focusEn":"work and discipline","oppEn":"steady foundations","avoidEn":"shortcuts and delays","focusHi":"काम और अनुशासन","oppHi":"मज़बूत नींव","avoidHi":"शॉर्टकट और देरी","focusTe":"పని, క్రమశిక్షణ","oppTe":"బలమైన పునాదులు","avoidTe":"షార్ట్‌కట్‌లు, ఆలస్యం"},"rahu":{"focusEn":"ambition and new paths","oppEn":"foreign and tech gains","avoidEn":"risky shortcuts","focusHi":"महत्वाकांक्षा और नए रास्ते","oppHi":"विदेश और तकनीक से लाभ","avoidHi":"जोखिम भरे शॉर्टकट","focusTe":"ఆకాంక్ష, కొత్త దారులు","oppTe":"విదేశం, టెక్నాలజీ లాభం","avoidTe":"రిస్క్ ఉన్న షార్ట్‌కట్‌లు"},"ketu":{"focusEn":"reflection and research","oppEn":"spiritual focus","avoidEn":"scattered energy","focusHi":"चिंतन और रिसर्च","oppHi":"आध्यात्मिक ध्यान","avoidHi":"बिखरी हुई ऊर्जा","focusTe":"చింతన, పరిశోధన","oppTe":"ఆధ్యాత్మిక దృష్టి","avoidTe":"చెల్లాచెదురైన శక్తి"}},"mLabels":{"focus":{"en":"Focus","hi":"ध्यान","te":"దృష్టి"},"opp":{"en":"Opportunity","hi":"मौक़ा","te":"అవకాశం"},"avoid":{"en":"Avoid","hi":"बचें","te":"దూరంగా"}}};})(typeof window!=='undefined'?window:global);
